package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserParseFileTest {

    File mockFile;
    CSVFormat mockFormat;

    @BeforeEach
    void setup() {
        mockFile = mock(File.class);
        mockFormat = mock(CSVFormat.class);
    }

    @Test
    void parse_nullFile_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((File) null, mockFormat));
        assertEquals("file", ex.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockFile, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_validFileAndFormat_returnsCSVParser() throws IOException {
        // Since mocking FileReader construction inside CSVParser.parse is not possible with Mockito 3,
        // we use a real temporary file instead of a mock File.
        java.nio.file.Path tempFile = java.nio.file.Files.createTempFile("csvparser-test", ".csv");
        try {
            CSVParser parser = CSVParser.parse(tempFile.toFile(), mockFormat);
            assertNotNull(parser);
            assertTrue(parser instanceof CSVParser);
        } finally {
            java.nio.file.Files.deleteIfExists(tempFile);
        }
    }
}
